// Calculate wait time until Chatzot (Halachic Noon)
const hebcalData = $input.first().json;
const chatzotISO = hebcalData.times.chatzot;

if (!chatzotISO) {
  // Fallback to 12:00 if API fails
  const now = new Date();
  now.setHours(12, 0, 0, 0);
  return [{
    json: {
      chatzotTime: now.toISOString(),
      waitSeconds: Math.max(0, (now.getTime() - Date.now()) / 1000)
    }
  }];
}

const chatzotDate = new Date(chatzotISO);
const waitMs = chatzotDate.getTime() - Date.now();
const waitSeconds = Math.max(0, Math.floor(waitMs / 1000));

return [{
  json: {
    chatzotTime: chatzotISO,
    waitSeconds
  }
}];

// Find nearest IMS stations with radiation sensor capability
const config = $('Load Config').first().json;
const items = $input.all();
const stations = items.map(item => item.json);

const LATITUDE = config.location.latitude;
const LONGITUDE = config.location.longitude;

// Filter stations with valid location data
const validStations = stations.filter(s =>
  s.location && s.location.latitude != null && s.location.longitude != null
);

// Sort by Euclidean distance from home coordinates
const sorted = validStations.map(s => {
  const dist = Math.sqrt(
    Math.pow(s.location.latitude - LATITUDE, 2) +
    Math.pow(s.location.longitude - LONGITUDE, 2)
  );
  return { station: s, distance: dist };
}).sort((a, b) => a.distance - b.distance);

// Return top N candidates
const candidates = sorted.slice(0, config.weather.stationSearchCount).map(s => ({
  stationId: s.station.stationId,
  name: s.station.name,
  distance: s.distance
}));

return [{ json: { candidates } }];

// Fetch weather data from nearest IMS station with radiation sensor
const candidates = $input.first().json.candidates;
const config = $('Load Config').first().json;
const IMS_TOKEN = config.secrets.IMS_API_TOKEN;

const now = new Date();
const twoHoursAgo = new Date(now.getTime() - 2 * 60 * 60 * 1000);

// Format dates for IMS API (auto-detect Israel timezone offset)
function formatDate(d) {
  // Use Intl to get the actual current offset for Asia/Jerusalem
  const formatter = new Intl.DateTimeFormat('en-IL', {
    timeZone: 'Asia/Jerusalem',
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', hour12: false
  });
  const parts = formatter.formatToParts(d);
  const year = parts.find(p => p.type === 'year').value;
  const month = parts.find(p => p.type === 'month').value;
  const day = parts.find(p => p.type === 'day').value;
  const hour = parts.find(p => p.type === 'hour').value;
  const minute = parts.find(p => p.type === 'minute').value;
  return year + '/' + month + '/' + day + ' ' + hour + ':' + minute;
}

const fromStr = encodeURIComponent(formatDate(twoHoursAgo));
const toStr = encodeURIComponent(formatDate(now));

for (const candidate of candidates) {
  try {
    const url = 'https://api.ims.gov.il/v1/envista/stations/' + candidate.stationId + '/data/?from=' + fromStr + '&to=' + toStr;

    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'Authorization': 'ApiToken ' + IMS_TOKEN },
      json: true
    });

    if (response && response.data && response.data.length > 0) {
      const latestPoint = response.data[response.data.length - 1];
      const hasGrad = latestPoint.channels.some(
        c => c.name === 'Grad' && c.value !== null
      );

      if (hasGrad) {
        const dataPoints = response.data.map(item => {
          const result = {
            datetime: item.datetime,
            rain: null,
            humidity: null,
            globalRadiation: null,
            temperature: null
          };

          item.channels.forEach(c => {
            if (c.status === 1) {
              if (c.name === 'Rain') result.rain = c.value;
              if (c.name === 'RH') result.humidity = c.value;
              if (c.name === 'Grad') result.globalRadiation = c.value;
              if (c.name === 'TD') result.temperature = c.value;
            }
          });

          return result;
        });

        return [{
          json: {
            stationId: candidate.stationId,
            stationName: candidate.name,
            dataPoints,
            success: true
          }
        }];
      }
    }
  } catch (e) {
    continue;
  }
}

return [{
  json: {
    success: false,
    reason: 'No station with radiation sensor found'
  }
}];

// Get Tuya access token using HMAC-SHA256 signature
const crypto = require('crypto');

const config = $('Load Config').first().json;
const TUYA_ACCESS_ID = config.secrets.TUYA_ACCESS_ID;
const TUYA_ACCESS_SECRET = config.secrets.TUYA_ACCESS_SECRET;
const API_URL = 'https://openapi.tuyaeu.com';

// Preserve AI decision from input for downstream
const aiInput = $input.first().json;

const timestamp = Date.now().toString();
const path = '/v1.0/token?grant_type=1';

// Calculate signature (no token for auth request)
const contentHash = crypto.createHash('sha256').update('').digest('hex');
const stringToSign = 'GET\n' + contentHash + '\n\n' + path;
const str = TUYA_ACCESS_ID + timestamp + stringToSign;
const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

const response = await this.helpers.httpRequest({
  method: 'GET',
  url: API_URL + path,
  headers: {
    't': timestamp,
    'sign': sign,
    'client_id': TUYA_ACCESS_ID,
    'sign_method': 'HMAC-SHA256'
  },
  json: true
});

if (response.success && response.result && response.result.access_token) {
  return [{ json: { token: response.result.access_token, isCloudy: aiInput.isCloudy, reason: aiInput.reason } }];
} else {
  throw new Error('Failed to get Tuya token: ' + JSON.stringify(response));
}

// Close both Tuya blinds using signed API requests
const crypto = require('crypto');

const config = $('Load Config').first().json;
const TUYA_ACCESS_ID = config.secrets.TUYA_ACCESS_ID;
const TUYA_ACCESS_SECRET = config.secrets.TUYA_ACCESS_SECRET;
const API_URL = 'https://openapi.tuyaeu.com';
const inputJson = $input.first().json;
const token = inputJson.token;

// Preserve AI decision data for downstream email node
const isCloudy = inputJson.isCloudy;
const reason = inputJson.reason;

const BLINDS = [
  config.devices.SHUTTER_RIGHT,
  config.devices.SHUTTER_LEFT
];

const results = [];

for (const deviceId of BLINDS) {
  const timestamp = Date.now().toString();
  const path = '/v1.0/devices/' + deviceId + '/commands';
  const body = JSON.stringify({ commands: [{ code: 'control', value: 'close' }] });

  const contentHash = crypto.createHash('sha256').update(body).digest('hex');
  const stringToSign = 'POST\n' + contentHash + '\n\n' + path;
  const str = TUYA_ACCESS_ID + token + timestamp + stringToSign;
  const sign = crypto.createHmac('sha256', TUYA_ACCESS_SECRET).update(str).digest('hex').toUpperCase();

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: API_URL + path,
    headers: {
      't': timestamp,
      'sign': sign,
      'client_id': TUYA_ACCESS_ID,
      'sign_method': 'HMAC-SHA256',
      'access_token': token,
      'Content-Type': 'application/json'
    },
    body: body,
    json: true
  });

  results.push({ deviceId, success: response.success, result: response });
}

return [{ json: { blindsResults: results, isCloudy, reason } }];

// Prepare HTML email with blinds status report
const inputData = $input.first().json;
const isCloudy = inputData.isCloudy;
const reason = inputData.reason;

const statusColor = isCloudy ? '#3498db' : '#e67e22';
const statusText = isCloudy ? 'התריסים נשארים פתוחים' : 'התריסים נסגרים כעת';
const icon = isCloudy ? '☁️' : '☀️';

const htmlBody = `
<div style="direction: rtl; font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; max-width: 600px; margin: auto; border: 1px solid #eee; border-radius: 10px; overflow: hidden; box-shadow: 0 4px 10px rgba(0,0,0,0.1);">
  <div style="background-color: ${statusColor}; color: white; padding: 20px; text-align: center;">
    <h1 style="margin: 0; font-size: 24px;">${icon} ${statusText}</h1>
  </div>
  <div style="padding: 30px; line-height: 1.6; color: #333;">
    <p style="font-size: 18px; font-weight: bold; margin-bottom: 10px;">ניתוח המערכת:</p>
    <div style="background-color: #f9f9f9; padding: 15px; border-right: 5px solid ${statusColor}; border-radius: 4px; margin-bottom: 20px; font-style: italic;">
      ${reason}
    </div>
    <p style="font-size: 14px; color: #777;">
      ההחלטה התקבלה על ידי בינה מלאכותית בהתבסס על נתוני השירות המטאורולוגי ב-2 השעות האחרונות.
    </p>
  </div>
  <div style="background-color: #f1f1f1; padding: 10px; text-align: center; font-size: 12px; color: #999;">
    AI Weather Automation System | n8n
  </div>
</div>
`;

return [{
  json: {
    to: $('Load Config').first().json.settings.NOTIFICATION_EMAIL,
    subject: 'עדכון מצב תריסים יומי - AI Weather',
    html: htmlBody,
    isCloudy,
    reason
  }
}];

// Weather data failed - default to safe mode (keep blinds open)
return [{
  json: {
    isCloudy: true,
    reason: 'לא ניתן היה לקבל נתוני מזג אוויר מהשירות המטאורולוגי. התריסים יישארו פתוחים ליתר ביטחון.'
  }
}];

// Build the AI prompt from weather data
const config = $('Load Config').first().json;

// --- DEBUG MODE: return mock in Gemini response format ---
// When Gemini node is disabled (pass-through), Parse AI Response gets this directly
if (config.debug && config.debug.mockAI) {
  const mockResult = config.debug.blinds && config.debug.blinds.mockResult;
  const isCloudy = mockResult !== false;
  const reason = isCloudy
    ? '🧪 MOCK: תריסים נשארים פתוחים'
    : '🧪 MOCK: תריסים נסגרים';
  return [{ json: {
    candidates: [{ content: { parts: [{ text: JSON.stringify({ isCloudy, reason }) }] } }]
  }}];
}

// --- PRODUCTION MODE ---
const weatherData = $input.first().json;

const MIN_RAD = config.weather.minRadiationForSunnyWm2;
const CLOUDY_PCT = config.weather.cloudyThresholdPercentage * 100;
const COLD_TEMP = config.weather.coldThresholdCelsius;

const prompt = "Analyze the following IMS weather data from the last 2 hours (10-minute intervals): " + JSON.stringify(weatherData) +
  ".\n\nYour task is to decide if the blinds should remain OPEN (isCloudy: true) or CLOSE (isCloudy: false)." +
  "\n\nData Context:" +
  "\n- 'globalRadiation' is measured in W/m^2. Values below " + MIN_RAD + " W/m^2 during daytime indicate cloudy conditions." +
  "\n- 'rain' > 0 indicates active rain." +
  "\n\nRules:" +
  "\n1. For each interval, determine if it is 'cloudy/rainy' (globalRadiation < " + MIN_RAD + " OR rain > 0) or 'sunny'." +
  "\n2. If more than " + CLOUDY_PCT + "% of the intervals were 'cloudy/rainy', return isCloudy: true." +
  "\n3. If it is currently sunny but it's a COLD day (temperature below " + COLD_TEMP + "\u00b0C), return isCloudy: true." +
  "\n4. Only return isCloudy: false if it is sunny AND the temperature is comfortably warm (" + COLD_TEMP + "\u00b0C or above)." +
  "\n5. Provide a detailed and clear reason for your decision in Hebrew." +
  "\n\nReturn JSON: {\"isCloudy\": boolean, \"reason\": string}";

const payload = {
  contents: [{ role: "user", parts: [{ text: prompt }] }],
  generationConfig: {
    responseMimeType: "application/json",
    responseSchema: {
      type: "object",
      properties: {
        isCloudy: { type: "boolean" },
        reason: { type: "string" }
      },
      required: ["isCloudy", "reason"]
    }
  }
};

return [{ json: payload }];

// Parse Gemini AI response
const config = $('Load Config').first().json;

// --- DEBUG MODE: safety net (normally handled by AI Failed node) ---
if (config.debug && config.debug.mockAI) {
  const mockResult = config.debug.blinds && config.debug.blinds.mockResult;
  const isCloudy = mockResult !== false;
  const reason = isCloudy
    ? '🧪 MOCK: תריסים נשארים פתוחים'
    : '🧪 MOCK: תריסים נסגרים';
  return [{ json: { isCloudy, reason } }];
}

// --- PRODUCTION MODE ---
const response = $input.first().json;

try {
  const text = response.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json|```/g, '').trim();
  const result = JSON.parse(cleaned);
  return [{ json: { isCloudy: result.isCloudy, reason: result.reason } }];
} catch (e) {
  const month = new Date().getMonth() + 1;
  const isSummer = config.settings.SUMMER_MONTHS.includes(month);

  if (isSummer) {
    return [{ json: { isCloudy: false, reason: 'שגיאה בפענוח תשובת AI. בחודשי הקיץ (חודש ' + month + '), כברירת מחדל התריסים נסגרים.' } }];
  } else {
    return [{ json: { isCloudy: true, reason: 'שגיאה בפענוח תשובת AI. בחודשי החורף (חודש ' + month + '), כברירת מחדל התריסים נשארים פתוחים.' } }];
  }
}

// Load project configuration from file
const fs = require('fs');
const config = JSON.parse(fs.readFileSync('/home/node/.n8n/config.json', 'utf8'));
return [{ json: config }];

// AI request failed - check if this is mock mode or real failure
const config = $('Load Config').first().json;

// --- DEBUG MODE: return mock result from config ---
if (config.debug && config.debug.mockAI) {
  const mockResult = config.debug.blinds && config.debug.blinds.mockResult;
  const isCloudy = mockResult !== false;
  const reason = isCloudy
    ? '🧪 MOCK: תריסים נשארים פתוחים (mockResult != false)'
    : '🧪 MOCK: תריסים נסגרים (mockResult: false)';
  return [{ json: { isCloudy, reason } }];
}

// --- PRODUCTION: seasonal fallback ---
const month = new Date().getMonth() + 1;
const isSummer = config.settings.SUMMER_MONTHS.includes(month);

if (isSummer) {
  return [{ json: { isCloudy: false, reason: 'חלה תקלה בניתוח הנתונים על ידי הבינה המלאכותית (השירות לא זמין). בחודשי הקיץ (חודש ' + month + '), כברירת מחדל התריסים נסגרים.' } }];
} else {
  return [{ json: { isCloudy: true, reason: 'חלה תקלה בניתוח הנתונים על ידי הבינה המלאכותית (השירות לא זמין). בחודשי החורף (חודש ' + month + '), כברירת מחדל התריסים נשארים פתוחים.' } }];
}
